export const QBANK_TOTAL = QBANK.total;

const _idx = {};
for (const g of QBANK.groups) for (const c of g.chapters) {
  c.count = c.questions.length;
  _idx[g.id + '/' + c.id] = { group: g, chapter: c };
}

export function qbFind(groupId, chapterId) {
  return _idx[groupId + '/' + chapterId] || null;
}

export function qbGroup(groupId) {
  return QBANK.groups.find(g => g.id === groupId) || null;
}
